    13→// under the License.
    14→
    15→package web
    16→
    17→import (
    18→	"net/http"
    19→	"strings"
    20→	"sync"
    21→)
    22→
    23→var (
    24→	// Known HTTP methods.
    25→	_HTTP_METHODS = map[string]bool{
    26→		"GET":     true,
    27→		"POST":    true,
    28→		"PUT":     true,
    29→		"DELETE":  true,
    30→		"PATCH":   true,
    31→		"OPTIONS": true,
    32→		"HEAD":    true,
    33→	}
    34→)
    35→
    36→// routeMap represents a thread-safe map for route tree.
    37→type routeMap struct {
    38→	lock   sync.RWMutex
    39→	routes map[string]map[string]*Leaf
    40→}
    41→
    42→// NewRouteMap initializes and returns a new routeMap.
    43→func newRouteMap() *routeMap {
    44→	rm := &routeMap{
    45→		routes: make(map[string]map[string]*Leaf),
    46→	}
    47→	for m := range _HTTP_METHODS {
    48→		rm.routes[m] = make(map[string]*Leaf)
    49→	}
    50→	return rm
    51→}
    52→
    53→// getLeaf returns Leaf object if a route has been registered.
    54→func (rm *routeMap) getLeaf(method, pattern string) *Leaf {
    55→	rm.lock.RLock()
    56→	defer rm.lock.RUnlock()
    57→
    58→	return rm.routes[method][pattern]
    59→}
    60→
    61→// add adds new route to route tree map.
    62→func (rm *routeMap) add(method, pattern string, leaf *Leaf) {
    63→	rm.lock.Lock()
    64→	defer rm.lock.Unlock()
    65→
    66→	rm.routes[method][pattern] = leaf
    67→}
    68→
    69→type group struct {
    70→	pattern  string
    71→	handlers []Handler
    72→}
    73→
    74→// Router represents a Macaron router layer.
    75→type Router struct {
    76→	m       *Macaron
    77→	routers map[string]*Tree
    78→	*routeMap
    79→	namedRoutes map[string]*Leaf
    80→
    81→	groups   []group
    82→	notFound http.HandlerFunc
    83→}
    84→
    85→func NewRouter() *Router {
    86→	return &Router{
    87→		routers:     make(map[string]*Tree),
    88→		routeMap:    newRouteMap(),
    89→		namedRoutes: make(map[string]*Leaf),
    90→	}
    91→}
    92→
    93→// Handle is a function that can be registered to a route to handle HTTP requests.
    94→// Like http.HandlerFunc, but has a third parameter for the values of wildcards (variables).
    95→type Handle func(http.ResponseWriter, *http.Request, map[string]string)
    96→
    97→// handle adds new route to the router tree.
    98→func (r *Router) handle(method, pattern string, handle Handle) {
    99→	method = strings.ToUpper(method)
   100→
   101→	var leaf *Leaf
   102→	// Prevent duplicate routes.
   103→	if leaf = r.getLeaf(method, pattern); leaf != nil {
   104→		return
   105→	}
   106→
   107→	// Validate HTTP methods.
   108→	if !_HTTP_METHODS[method] && method != "*" {
   109→		panic("unknown HTTP method: " + method)
   110→	}
   111→
   112→	// Generate methods need register.
   113→	methods := make(map[string]bool)
   114→	if method == "*" {
   115→		for m := range _HTTP_METHODS {
   116→			methods[m] = true
   117→		}
   118→	} else {
   119→		methods[method] = true
   120→	}
   121→
   122→	// Add to router tree.
   123→	for m := range methods {
   124→		if t, ok := r.routers[m]; ok {
   125→			leaf = t.Add(pattern, handle)
   126→		} else {
   127→			t := NewTree()
   128→			leaf = t.Add(pattern, handle)
   129→			r.routers[m] = t
   130→		}
   131→		r.add(m, pattern, leaf)
   132→	}
   133→}
   134→
   135→// Handle registers a new request handle with the given pattern, method and handlers.
   136→func (r *Router) Handle(method string, pattern string, handlers []Handler) {
   137→	if len(r.groups) > 0 {
   138→		groupPattern := ""
   139→		h := make([]Handler, 0)
   140→		for _, g := range r.groups {
   141→			groupPattern += g.pattern
   142→			h = append(h, g.handlers...)
   143→		}
   144→
   145→		pattern = groupPattern + pattern
   146→		h = append(h, handlers...)
   147→		handlers = h
   148→	}
   149→
   150→	r.handle(method, pattern, func(resp http.ResponseWriter, req *http.Request, params map[string]string) {
   151→		c := r.m.createContext(resp, SetURLParams(req, params))
   152→		for _, h := range handlers {
   153→			c.mws = append(c.mws, mwFromHandler(h))
   154→		}
   155→		c.run()
   156→	})
   157→}
   158→
   159→func (r *Router) Group(pattern string, fn func(), h ...Handler) {
   160→	r.groups = append(r.groups, group{pattern, h})
   161→	fn()
   162→	r.groups = r.groups[:len(r.groups)-1]
   163→}
   164→
   165→// Get is a shortcut for r.Handle("GET", pattern, handlers)
   166→func (r *Router) Get(pattern string, h ...Handler) {
   167→	r.Handle("GET", pattern, h)
   168→	r.Head(pattern, h...)
   169→}
   170→
   171→// Patch is a shortcut for r.Handle("PATCH", pattern, handlers)
   172→func (r *Router) Patch(pattern string, h ...Handler) { r.Handle("PATCH", pattern, h) }
   173→
   174→// Post is a shortcut for r.Handle("POST", pattern, handlers)
   175→func (r *Router) Post(pattern string, h ...Handler) { r.Handle("POST", pattern, h) }
   176→
   177→// Put is a shortcut for r.Handle("PUT", pattern, handlers)
   178→func (r *Router) Put(pattern string, h ...Handler) { r.Handle("PUT", pattern, h) }
   179→
   180→// Delete is a shortcut for r.Handle("DELETE", pattern, handlers)
   181→func (r *Router) Delete(pattern string, h ...Handler) { r.Handle("DELETE", pattern, h) }
   182→
   183→// Options is a shortcut for r.Handle("OPTIONS", pattern, handlers)
   184→func (r *Router) Options(pattern string, h ...Handler) { r.Handle("OPTIONS", pattern, h) }
   185→
   186→// Head is a shortcut for r.Handle("HEAD", pattern, handlers)
   187→func (r *Router) Head(pattern string, h ...Handler) { r.Handle("HEAD", pattern, h) }
   188→
   189→// Any is a shortcut for r.Handle("*", pattern, handlers)
   190→func (r *Router) Any(pattern string, h ...Handler) { r.Handle("*", pattern, h) }
