     8→	"github.com/grafana/grafana/pkg/web"
     9→)
    10→
    11→type Router interface {
    12→	Handle(method, pattern string, handlers []web.Handler)
    13→	Get(pattern string, handlers ...web.Handler)
    14→}
    15→
    16→// RouteRegister allows you to add routes and web.Handlers
    17→// that the web server should serve.
    18→type RouteRegister interface {
    19→	// Get adds a list of handlers to a given route with a GET HTTP verb
    20→	Get(string, ...web.Handler)
    21→
    22→	// Post adds a list of handlers to a given route with a POST HTTP verb
    23→	Post(string, ...web.Handler)
    24→
    25→	// Delete adds a list of handlers to a given route with a DELETE HTTP verb
    26→	Delete(string, ...web.Handler)
    27→
    28→	// Put adds a list of handlers to a given route with a PUT HTTP verb
    29→	Put(string, ...web.Handler)
    30→
    31→	// Patch adds a list of handlers to a given route with a PATCH HTTP verb
    32→	Patch(string, ...web.Handler)
    33→
    34→	// Any adds a list of handlers to a given route with any HTTP verb
    35→	Any(string, ...web.Handler)
    36→
    37→	// Group allows you to pass a function that can add multiple routes
    38→	// with a shared prefix route.
    39→	Group(string, func(RouteRegister), ...web.Handler)
    40→
    41→	// Insert adds more routes to an existing Group.
    42→	Insert(string, func(RouteRegister), ...web.Handler)
    43→
    44→	// Register iterates over all routes added to the RouteRegister
    45→	// and add them to the `Router` pass as an parameter.
    46→	Register(Router, ...RegisterNamedMiddleware)
    47→
    48→	// Reset resets the route register.
    49→	Reset()
    50→}
    51→
    52→type RegisterNamedMiddleware func(name string) web.Handler
    53→
    54→func ProvideRegister() *RouteRegisterImpl {
    55→	return NewRouteRegister(middleware.ProvideRouteOperationName)
    56→}
    57→
    58→// NewRouteRegister creates a new RouteRegister with all middlewares sent as params
    59→func NewRouteRegister(namedMiddlewares ...RegisterNamedMiddleware) *RouteRegisterImpl {
    60→	return &RouteRegisterImpl{
    61→		prefix:           "",
    62→		routes:           []route{},
    63→		subfixHandlers:   []web.Handler{},
    64→		namedMiddlewares: namedMiddlewares,
    65→	}
    66→}
    67→
    68→type route struct {
    69→	method   string
    70→	pattern  string
    71→	handlers []web.Handler
    72→}
    73→
    74→type RouteRegisterImpl struct {
    75→	prefix           string
    76→	subfixHandlers   []web.Handler
    77→	namedMiddlewares []RegisterNamedMiddleware
    78→	routes           []route
    79→	groups           []*RouteRegisterImpl
    80→}
    81→
    82→func (rr *RouteRegisterImpl) Reset() {
    83→	if rr == nil {
    84→		return
    85→	}
    86→
    87→	rr.routes = nil
    88→	rr.groups = nil
    89→	rr.subfixHandlers = nil
    90→}
    91→
    92→func (rr *RouteRegisterImpl) Insert(pattern string, fn func(RouteRegister), handlers ...web.Handler) {
    93→	// loop over all groups at current level
    94→	for _, g := range rr.groups {
    95→		// apply routes if the prefix matches the pattern
    96→		if g.prefix == pattern {
    97→			g.Group("", fn)
    98→			break
    99→		}
   100→
   101→		// go down one level if the prefix can be find in the pattern
   102→		if strings.HasPrefix(pattern, g.prefix) {
   103→			g.Insert(pattern, fn)
   104→		}
   105→	}
   106→}
   107→
   108→func (rr *RouteRegisterImpl) Group(pattern string, fn func(rr RouteRegister), handlers ...web.Handler) {
   109→	group := &RouteRegisterImpl{
   110→		prefix:           rr.prefix + pattern,
   111→		subfixHandlers:   append(rr.subfixHandlers, handlers...),
   112→		routes:           []route{},
   113→		namedMiddlewares: rr.namedMiddlewares,
   114→	}
   115→
   116→	fn(group)
   117→	rr.groups = append(rr.groups, group)
   118→}
   119→
   120→func (rr *RouteRegisterImpl) Register(router Router, namedMiddlewares ...RegisterNamedMiddleware) {
   121→	for _, r := range rr.routes {
   122→		// Add global named middlewares
   123→		for i, m := range namedMiddlewares {
   124→			r.handlers = insertHandler(r.handlers, len(rr.namedMiddlewares)+i, m(r.pattern))
   125→		}
   126→
   127→		// GET requests have to be added to macaron routing using Get()
   128→		// Otherwise HEAD requests will not be allowed.
   129→		// https://github.com/go-macaron/macaron/blob/a325110f8b392bce3e5cdeb8c44bf98078ada3be/router.go#L198
   130→		if r.method == http.MethodGet {
   131→			router.Get(r.pattern, r.handlers...)
   132→		} else {
   133→			router.Handle(r.method, r.pattern, r.handlers)
   134→		}
   135→	}
   136→
   137→	for _, g := range rr.groups {
   138→		g.Register(router, namedMiddlewares...)
   139→	}
   140→}
   141→
   142→func (rr *RouteRegisterImpl) route(pattern, method string, handlers ...web.Handler) {
   143→	h := make([]web.Handler, 0)
   144→	fullPattern := rr.prefix + pattern
   145→
   146→	for _, fn := range rr.namedMiddlewares {
   147→		h = append(h, fn(fullPattern))
   148→	}
   149→
   150→	h = append(h, rr.subfixHandlers...)
   151→	h = append(h, handlers...)
   152→
   153→	for _, r := range rr.routes {
   154→		if r.pattern == fullPattern && r.method == method {
   155→			panic("cannot add duplicate route")
   156→		}
   157→	}
   158→
   159→	rr.routes = append(rr.routes, route{
   160→		method:   method,
   161→		pattern:  fullPattern,
   162→		handlers: h,
   163→	})
   164→}
   165→
   166→func insertHandler(a []web.Handler, index int, value web.Handler) []web.Handler {
   167→	if len(a) == index {
   168→		return append(a, value)
   169→	}
   170→	a = append(a[:index+1], a[index:]...)
   171→	a[index] = value
   172→	return a
   173→}
   174→
   175→func (rr *RouteRegisterImpl) Get(pattern string, handlers ...web.Handler) {
   176→	rr.route(pattern, http.MethodGet, handlers...)
   177→}
   178→
   179→func (rr *RouteRegisterImpl) Post(pattern string, handlers ...web.Handler) {
   180→	rr.route(pattern, http.MethodPost, handlers...)
   181→}
   182→
   183→func (rr *RouteRegisterImpl) Delete(pattern string, handlers ...web.Handler) {
   184→	rr.route(pattern, http.MethodDelete, handlers...)
   185→}
